#!/bin/bash

# Check if no directories are provided
if [ $# -eq 0 ]; then
  echo "Usage: $0 directory1 directory2 ..."
  exit 1
fi

# Create a timestamp for the backup file
TIMESTAMP=$(date +%Y%m%d%H%M%S)

# Initialize an empty string to hold the list of directories
DIRECTORIES=""

# Loop through all arguments and add them to the DIRECTORIES variable
for dir in "$@"; do
  if [ -d "$dir" ]; then
    DIRECTORIES+="$dir "
  else
    echo "Directory $dir does not exist."
